const raw = $input.all()[0]?.json ?? {};
let payload = raw.query ?? {};
let parseError = false;

if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (error) {
    payload = {};
    parseError = true;
  }
}

if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
  payload = {};
  parseError = true;
}

function str(value) {
  return String(value ?? '').trim();
}

function boolOrNull(value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value === 'boolean') return value;
  const text = str(value).toLowerCase();
  if (['true', '1', 'yes', 'done', 'completed', '已完成', '完成'].includes(text)) return true;
  if (['false', '0', 'no', 'todo', 'open', 'incomplete', '未完成', '待办'].includes(text)) return false;
  return null;
}

function finish(ok, output, extra = {}, errorCode = 'LARK_READ_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: extra.action || action || 'unknown_action',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

function parseAllowedMentions(value) {
  let source = value;
  if (typeof source === 'string') {
    try {
      source = JSON.parse(source || '[]');
    } catch (error) {
      source = [];
    }
  }
  if (!Array.isArray(source)) return [];
  const seen = new Set();
  const users = [];
  for (const item of source) {
    const id = str(item.openId || item.open_id || item.id || item.userId || item.user_id);
    if (!id || seen.has(id)) continue;
    seen.add(id);
    users.push({
      openId: id,
      name: str(item.name || item.displayName || item.localizedName),
    });
  }
  return users.slice(0, 10);
}

const trusted = {
  senderOpenId: str(raw.trustedSenderOpenId),
  messageId: str(raw.trustedMessageId),
  messageText: str(raw.trustedMessageText),
  chatId: str(raw.trustedChatId),
  sessionKey: str(raw.trustedSessionKey),
};

let action = str(payload.action || payload.operation || payload.tool);
const aliases = {
  tasks: 'list_my_tasks',
  my_tasks: 'list_my_tasks',
  list_tasks: 'list_my_tasks',
  list_my_task: 'list_my_tasks',
  get_tasks: 'list_my_tasks',
  mentioned_users: 'get_mentioned_users',
  get_mentions: 'get_mentioned_users',
  get_mentioned_contacts: 'get_mentioned_users',
  contact_mentions: 'get_mentioned_users',
  get_user: 'get_user_basic',
  get_contact: 'get_user_basic',
  lookup_contact: 'get_user_basic',
  user_profile: 'get_user_basic',
};
action = aliases[action] || action;

const supportedActions = ['list_my_tasks', 'get_mentioned_users', 'get_user_basic'];
if (!action && /任务|待办|todo|task/i.test(trusted.messageText)) action = 'list_my_tasks';
if (!action && /通讯录|联系人|成员|用户|同事|user|contact/i.test(trusted.messageText)) action = 'get_mentioned_users';

if (parseError) return finish(false, '读取工具参数不是有效 JSON。', { action: 'unknown_action' }, 'INVALID_TOOL_INPUT');
if (!supportedActions.includes(action)) {
  return finish(false, 'lark_read_tools 不支持 action：' + (action || 'unknown') + '。', {
    action: action || 'unknown_action',
    supportedActions,
  }, 'UNSUPPORTED_ACTION');
}
if (!trusted.senderOpenId || !trusted.messageId || !trusted.sessionKey) {
  return finish(false, '缺少可信消息上下文，不能读取飞书数据。', { action }, 'MISSING_TRUSTED_CONTEXT');
}

const identityFields = ['targetUserId', 'target_user_id', 'assigneeId', 'assignee_id', 'open_id', 'openId', 'userId', 'user_id'];
if (action === 'list_my_tasks') {
  const supplied = identityFields.map((field) => str(payload[field])).find(Boolean);
  if (supplied && supplied !== trusted.senderOpenId && supplied !== 'me') {
    return finish(false, '第一版只允许读取你自己负责的任务。', { action }, 'READ_SELF_TASKS_ONLY');
  }

  const completed = boolOrNull(payload.completed ?? payload.complete ?? payload.done ?? payload.status);
  const query = str(payload.query || payload.keyword || payload.text).slice(0, 100);
  const pageToken = str(payload.pageToken || payload.page_token).slice(0, 200);
  const taskListParams = {
    type: 'my_tasks',
    user_id_type: 'open_id',
    page_size: 50,
  };
  if (completed !== null) taskListParams.completed = completed;
  if (pageToken) taskListParams.page_token = pageToken;
  const queryString = Object.entries(taskListParams)
    .map(([key, value]) => encodeURIComponent(key) + '=' + encodeURIComponent(String(value)))
    .join('&');
  const taskListUrl = 'https://open.feishu.cn/open-apis/task/v2/tasks?' + queryString;

  return finish(true, '准备读取你负责的飞书任务。', {
    action,
    trusted,
    taskListParams,
    taskListUrl,
    filters: { completed, query, pageToken },
  });
}

const allowedMentions = parseAllowedMentions(raw.allowedContactUserIdsJson || raw.allowedContactUserIds);
const allowedSet = new Set([trusted.senderOpenId, ...allowedMentions.map((user) => user.openId)]);
let contactUserIds = [];

if (action === 'get_mentioned_users') {
  contactUserIds = allowedMentions.map((user) => user.openId);
  if (!contactUserIds.length) {
    return finish(false, '这条消息里没有可读取的 @ 用户。', { action, allowedMentions }, 'NO_MENTIONED_USERS');
  }
} else {
  let targetUserId = str(payload.targetUserId || payload.target_user_id || payload.userId || payload.user_id || payload.openId || payload.open_id || payload.id);
  if (!targetUserId || targetUserId === 'me' || targetUserId === 'self') targetUserId = trusted.senderOpenId;
  if (!allowedSet.has(targetUserId)) {
    return finish(false, '第一版只允许读取你自己或当前消息里被 @ 的用户资料。', {
      action,
      targetUserId,
      allowedMentions,
    }, 'CONTACT_TARGET_NOT_ALLOWED');
  }
  contactUserIds = [targetUserId];
}

const dedupedContactUserIds = [...new Set(contactUserIds)].slice(0, 10);
return finish(true, '准备读取通讯录基础信息。', {
  action,
  trusted,
  allowedMentions,
  contactUserIds: dedupedContactUserIds,
  contactSearchBody: {
    filter: { user_ids: dedupedContactUserIds },
  },
  contactPageSize: Math.min(Math.max(dedupedContactUserIds.length || 1, 1), 10),
});

const input = $input.all()[0]?.json ?? {};
const request = $('Normalize').all()[0]?.json ?? {};

function finish(ok, output, extra = {}, errorCode = 'LIST_MY_TASKS_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: 'list_my_tasks',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function firstString(...values) {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return '';
}

function formatTime(value) {
  const raw = firstString(value?.timestamp, value);
  if (!raw) return '';
  const number = Number(raw);
  if (!Number.isFinite(number)) return '';
  try {
    return new Intl.DateTimeFormat('zh-CN', {
      timeZone: 'Asia/Shanghai',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
    }).format(new Date(number));
  } catch (error) {
    return '';
  }
}

function taskFrom(item) {
  return item?.task && typeof item.task === 'object' ? item.task : item;
}

if (!request.ok) return finish(false, request.output || '读取请求未通过校验。', request, request.error?.code || 'REQUEST_INVALID');
if (input.error) {
  const detail = typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error));
  return finish(false, '读取飞书任务失败：' + detail, { data: { tasks: [] } }, 'READ_TASKS_FAILED');
}
if (input.code && input.code !== 0) {
  return finish(false, '读取飞书任务失败：' + (input.msg || JSON.stringify(input)), { data: { tasks: [] } }, 'READ_TASKS_API_ERROR');
}

const data = input.data && typeof input.data === 'object' ? input.data : input;
const rawItems = asArray(data.items || data.tasks || input.items || input.tasks);
const query = firstString(request.filters?.query).toLowerCase();
const allTasks = rawItems.map(taskFrom).filter(Boolean);
const matchedTasks = query
  ? allTasks.filter((task) => {
      const haystack = [task.summary, task.title, task.name, task.task_id, task.suite_entity_num]
        .map((value) => firstString(value).toLowerCase())
        .join(' ');
      return haystack.includes(query);
    })
  : allTasks;
const tasks = matchedTasks.slice(0, 10).map((task) => {
  const guid = firstString(task.guid, task.task_guid, task.id);
  const summary = firstString(task.summary, task.title, task.name, '(未命名任务)').slice(0, 120);
  const status = firstString(task.status) || (task.completed_at ? 'done' : 'todo');
  const dueText = formatTime(task.due);
  const startText = formatTime(task.start);
  const updatedAt = formatTime(task.updated_at);
  return {
    guid,
    taskId: firstString(task.task_id, task.suite_entity_num),
    summary,
    status,
    dueText,
    startText,
    updatedAt,
    url: firstString(task.url),
  };
});

const hasMore = Boolean(data.has_more || data.hasMore);
const pageToken = firstString(data.page_token, data.pageToken);

if (!tasks.length) {
  const scope = query ? '匹配“' + request.filters.query + '”的' : '';
  return finish(true, '✅ 没有找到你负责的' + scope + '飞书任务。', {
    data: { tasks, count: 0, fetchedCount: allTasks.length, hasMore, pageToken, filters: request.filters || {} },
  });
}

const lines = ['✅ 找到 ' + tasks.length + ' 个你负责的任务' + (hasMore ? '，还有更多。' : '。')];
for (const [index, task] of tasks.slice(0, 5).entries()) {
  const bits = [String(index + 1) + '. ' + task.summary];
  if (task.status) bits.push(task.status === 'done' ? '已完成' : '未完成');
  if (task.dueText) bits.push('截止 ' + task.dueText);
  lines.push(bits.join(' · '));
}
if (hasMore && pageToken) lines.push('📌 还有更多结果，可继续读取下一页。');

return finish(true, lines.join('\n'), {
  data: {
    tasks,
    count: tasks.length,
    hasMore,
    pageToken,
    filters: request.filters || {},
  },
});

const items = $input.all();
const request = $('Normalize').all()[0]?.json ?? {};

function finish(ok, output, extra = {}, errorCode = 'READ_CONTACTS_FAILED') {
  return [{
    json: {
      ...extra,
      ok,
      action: request.action || 'get_user_basic',
      version: 'v1',
      error: ok ? null : { code: errorCode, message: output, retryable: false },
      output,
    },
  }];
}

function firstString(...values) {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return '';
}

function userFrom(input) {
  return input?.data?.user || input?.user || input?.data || input;
}

if (!request.ok) return finish(false, request.output || '读取请求未通过校验。', request, request.error?.code || 'REQUEST_INVALID');

const apiErrors = [];
const users = [];
for (const item of items) {
  const input = item?.json ?? {};
  if (input.error) {
    apiErrors.push(typeof input.error === 'string' ? input.error : (input.error.message || JSON.stringify(input.error)));
    continue;
  }
  if (input.code && input.code !== 0) {
    apiErrors.push(input.msg || JSON.stringify(input));
    continue;
  }
  const user = userFrom(input);
  const openId = firstString(user.open_id, user.openId, user.user_id, user.id, input.contactUserId);
  const displayName = firstString(user.localized_name, user.name, user.en_name, user.nickname, openId);
  const department = firstString(user.department, user.department_path, user.department_name);
  if (openId || displayName) {
    users.push({
      openId,
      displayName,
      department,
      isActivated: typeof user.is_activated === 'boolean' ? user.is_activated : null,
      isCrossTenant: typeof user.is_cross_tenant === 'boolean' ? user.is_cross_tenant : null,
    });
  }
}

if (!users.length && apiErrors.length) {
  return finish(false, '读取通讯录失败：' + apiErrors[0], { data: { users: [], errors: apiErrors.slice(0, 3) } }, 'READ_CONTACTS_API_ERROR');
}

if (!users.length) {
  return finish(true, '⚠️ 没有读取到可展示的通讯录信息。', {
    data: { users, count: 0 },
  });
}

const lines = ['✅ 读取到 ' + users.length + ' 个用户基础信息。'];
for (const user of users.slice(0, 5)) {
  const bits = [user.displayName];
  if (user.department) bits.push(user.department);
  if (user.isActivated === false) bits.push('未激活');
  if (user.isCrossTenant === true) bits.push('外部联系人');
  lines.push(bits.join(' · '));
}

return finish(true, lines.join('\n'), {
  data: { users, count: users.length, partialErrors: apiErrors.slice(0, 3) },
});

const request = $('Normalize').all()[0]?.json ?? {};
return [{
  json: {
    ok: false,
    action: request.action || 'unknown_action',
    version: 'v1',
    error: request.error || {
      code: 'LARK_READ_GUARD_FAILED',
      message: request.output || '读取请求未通过校验。',
      retryable: false,
    },
    supportedActions: request.supportedActions || ['list_my_tasks', 'get_mentioned_users', 'get_user_basic'],
    output: request.output || '读取请求未通过校验。',
  },
}];

const request = $('Normalize').all()[0]?.json ?? {};
if (!request.ok) return [{ json: request }];
const ids = Array.isArray(request.contactUserIds) ? request.contactUserIds : [];
return ids.map((contactUserId) => ({
  json: {
    ...request,
    contactUserId,
  },
}));
